#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e3 + 5;
int f[N][10][10], mod = 1e9 + 7, ans;
string l, r;
void dp () {
	for (int i = 2; i <= 1000; i++) {
		for (int x = 0; x <= 9; x++) {
			for (int y = 0; y <= 9; y++) {
				if (x != y) {
					for (int z = 0; z <= 9; z++) {
						if (y != z && x != z) {
							f[i][x][y] += f[i - 1][y][z];
						}
					}
					if (i - 1 == 1) {
						f[i][x][y]++;
					}
					f[i][x][y] %= mod;
				}
			}
		}
	}
	return;
}
int out (string s) {
	int n = s.size (), X = -1, Y = -1;
	int tot = 0, ans = 0;
	bool ok = 1;
	for (int i = 0; i < n; i++) {
		tot = (tot * 10 + s[i] - 48) % mod;
	}
	for (int i = 1; i < n; i++) {
		for (int x = 1; x <= 9; x++) {
			for (int y = 0; y <= 9; y++) {
				ans = (ans + f[i][x][y]) % mod;
			}
		}
	}
	if (n > 1) {
		ans += 10;
	}
	for (int i = n; i > 1; i--) {
		int v = s[n - i] - 48;
		for (int j = 0; j < v; j++) {
			if (i != n || j != 0) {
				for (int k = 0; k <= 9; k++) {
					if (X != j && Y != j && j != k && k != X) {
						ans = (ans + f[i][j][k]) % mod;
					}
				}
			}
		}
		if (v == X || v == Y) {
			ok = 0;
			break;
		}
		Y = X;
		X = v;
	}
	if (ok) {
		for (int j = 0; j <= s[n - 1] - 48; j++) {
			if (j != Y && j != X) {
				ans = (ans + 1 + mod) % mod;
			}
		}
	}
	return (tot + 1 - ans) % mod;
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	dp ();
	cin >> l >> r;
	ans = (out (r) - out (l)) % mod;
	for (int i = 1; i <= l.size () - 1; i++) {
		if (l[i] == l[i - 1] || (i > 1 && l[i] == l[i - 2])) {
			ans = (ans + 1 + mod) % mod;
			break;
		}
	}
	cout << ans;
	return 0;
}
